import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './DataTable.css';

const DataTable = () => {
  const [data, setData] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [sortConfig, setSortConfig] = useState({ key: null, direction: 'asc' });
  const [currentPage, setCurrentPage] = useState(1);
  const [itemsPerPage, setItemsPerPage] = useState(10);
  const [rowsPerPageOptions] = useState([10, 25, 50]);
  const [showModal, setShowModal] = useState(false);
  const [selectedRow, setSelectedRow] = useState(null);

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const response = await axios.get('https://jsonplaceholder.typicode.com/users');
      const fetchedData = response.data;

      // Repeat fetched data 10-15 times to get 100 rows
      let repeatedData = [];
      for (let i = 0; i < 10; i++) {
        repeatedData = repeatedData.concat(
          fetchedData.map((item) => ({
            ...item,
            id: item.id + i * fetchedData.length,
          }))
        );
      }

      setData(repeatedData);
    } catch (error) {
      console.error('Error fetching data:', error);
    }
  };

  const handleSearch = (event) => {
    setSearchTerm(event.target.value);
  };

  const handleRowsPerPageChange = (event) => {
    setItemsPerPage(parseInt(event.target.value, 10));
    setCurrentPage(1); // Reset current page to the first page
  };

  const handleSort = (key) => {
    let direction = 'asc';
    if (sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });
  };

  const handlePageClick = (newPage) => {
    setCurrentPage(newPage);
  };

  const handleEditClick = (rowData) => {
    setSelectedRow(rowData);
    setShowModal(true);
  };

  const handleModalClose = () => {
    setShowModal(false);
  };

  const handleSave = () => {
    // Update the data state with the edited row data
    setData((prevData) =>
      prevData.map((item) => (item.id === selectedRow.id ? selectedRow : item))
    );

    // Close the modal
    handleModalClose();

    // Uncomment and update the endpoint to send the updated data to the server
    // axios.put(`https://yourapi.com/users/${selectedRow.id}`, selectedRow)
    // .then((response) => {
    //   console.log('Data saved:', response.data);
    // })
    // .catch((error) => {
    //   console.error('Error saving data:', error);
    // });
  };

  // Sorting the data
  const sortedData = React.useMemo(() => {
    let sortableItems = [...data];
    if (sortConfig.key) {
      sortableItems.sort((a, b) => {
        if (a[sortConfig.key] < b[sortConfig.key]) {
          return sortConfig.direction === 'asc' ? -1 : 1;
        }
        if (a[sortConfig.key] > b[sortConfig.key]) {
          return sortConfig.direction === 'asc' ? 1 : -1;
        }
        return 0;
      });
    }
    return sortableItems;
  }, [data, sortConfig]);

  const filteredData = sortedData.filter((item) =>
    item.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const totalPages = Math.ceil(filteredData.length / itemsPerPage);
  const startIndex = (currentPage - 1) * itemsPerPage;
  const endIndex = startIndex + itemsPerPage;
  const currentData = filteredData.slice(startIndex, endIndex);

  return (
    <div className='container'>
      <div className='search-bar'>
        <div className="search-wrapper">
          <input
            type="text"
            placeholder="Search by name"
            value={searchTerm}
            onChange={handleSearch}
            className='search-input'
          />
          <i className="search-icon fas fa-search"></i>
        </div>
      </div>
      <table className="table">
        <thead>
          <tr>
            <th onClick={() => handleSort('id')}>ID</th>
            <th onClick={() => handleSort('name')}>Name</th>
            <th onClick={() => handleSort('email')}>Email</th>
            <th onClick={() => handleSort('address.city')}>City</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {currentData.map((item) => (
            <tr key={item.id}>
              <td>{item.id}</td>
              <td>{item.name}</td>
              <td>{item.email}</td>
              <td>{item.address.city}</td>
              <td>
                <button onClick={() => handleEditClick(item)}>Edit</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
      <div className="pagination-options">
        <div className="rows-per-page">
          Rows per page:
          <select value={itemsPerPage} onChange={handleRowsPerPageChange}>
            {rowsPerPageOptions.map((option) => (
              <option key={option} value={option}>
                {option}
              </option>
            ))}
          </select>
        </div>
        <div className="pagination">
          <button
            onClick={() => handlePageClick(1)}
            disabled={currentPage === 1}
          >
            First
          </button>
          <button
            onClick={() => handlePageClick(currentPage - 1)}
            disabled={currentPage === 1}
          >
            Previous
          </button>
          {Array.from({ length: totalPages }, (_, index) => index + 1).map(
            (page) => (
              <button
                key={page}
                onClick={() => handlePageClick(page)}
                disabled={currentPage === page}
              >
                {page}
              </button>
            )
          )}
          <button
            onClick={() => handlePageClick(currentPage + 1)}
            disabled={currentPage === totalPages}
          >
            Next
          </button>
          <button
            onClick={() => handlePageClick(totalPages)}
            disabled={currentPage === totalPages}
          >
            Last
          </button>
        </div>
      </div>

      {showModal && (
        <div className="modal">
          <div className="modal-content">
            <h2>Edit User</h2>
            <form>
              <label>ID:</label>
              <input type="text" value={selectedRow?.id} readOnly />

              <label>Name:</label>
              <input
                type="text"
                value={selectedRow?.name}
                onChange={(e) =>
                  setSelectedRow((prev) => ({ ...prev, name: e.target.value }))
                }
              />

              <label>Email:</label>
              <input
                type="text"
                value={selectedRow?.email}
                onChange={(e) =>
                  setSelectedRow((prev) => ({ ...prev, email: e.target.value }))
                }
              />

              <label>City:</label>
              <input
                type="text"
                value={selectedRow?.address.city}
                onChange={(e) =>
                  setSelectedRow((prev) => ({
                    ...prev,
                    address: { ...prev.address, city: e.target.value },
                  }))
                }
              />
            </form>
            <button onClick={handleSave}>Save</button>
            <button onClick={handleModalClose}>Close</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default DataTable;
